// Pattern:
// If a Postgres node precedes a binary consumer,
// restore binary from the trigger using node reference.
//
// Here: 'Load OCR Provider Settings' (Postgres) sits between the trigger and the Azure
// node. Postgres replaces the item and drops item.binary, so the Azure node would not see
// the file. We restore it from the trigger by node reference (verified working: the boundary
// probe resolved $('When Executed by WF-001').first().binary and getBinaryDataBuffer read the
// full file). json (the loaded OCR settings) passes through unchanged.
return [{ json: $json, binary: $('When Executed by WF-001').first().binary }];

// SUBMIT ADAPTER (provider-independent shell; Azure defaults).
// Extracts the poll URL from the submit response using provider config, and initialises poll state.
const cfg  = $('Load OCR Provider Settings').first().json.settings || {};
const poll = cfg.poll || {};
const HDR  = (poll.pollUrlHeader   || 'operation-location').toLowerCase();
const IVAL = Number(poll.pollIntervalMs ?? 2000);   // Azure: no faster than ~2s
const MAXA = Number(poll.maxAttempts    ?? 90);     // budget: 90 attempts
const MAXMS= Number(poll.maxElapsedMs   ?? 900000); // budget: 15 min hard ceiling

const res = $json;                       // fullResponse: { statusCode, headers, body }
const headers = res.headers || {};
// header lookup is case-insensitive
let pollUrl = null;
for (const k of Object.keys(headers)) { if (k.toLowerCase() === HDR) { pollUrl = headers[k]; break; } }
const status = res.statusCode;

if (status !== 202 || !pollUrl) {
  // Submit itself failed -> terminal failure, no polling.
  return [{ json: {
    _poll: { terminal: true, status: 'failed', attempt: 0, startedAt: Date.now(),
             intervalMs: IVAL, maxAttempts: MAXA, maxElapsedMs: MAXMS,
             error: `submit failed: HTTP ${status}` + (pollUrl ? '' : ' (no poll URL header)') },
    _result: null
  }}];
}
// Honor Retry-After from the submit response if present.
let firstWaitMs = IVAL;
const ra = headers['retry-after'] || headers['Retry-After'];
if (ra && !isNaN(Number(ra))) firstWaitMs = Math.max(IVAL, Number(ra) * 1000);

return [{ json: {
  _poll: { pollUrl, terminal: false, status: 'notStarted', attempt: 0, startedAt: Date.now(),
           waitMs: firstWaitMs, intervalMs: IVAL, maxAttempts: MAXA, maxElapsedMs: MAXMS, error: null },
  _result: null
}}];

// POLL ADAPTER (provider-independent shell; Azure defaults).
// Normalises the provider response to { status, result } and enforces the timeout budget.
const cfg  = $('Load OCR Provider Settings').first().json.settings || {};
const pc   = cfg.poll || {};
const STATUS_PATH = pc.statusPath      || 'status';
const SUCCESS     = pc.terminalSuccess || 'succeeded';
const FAILURE     = pc.terminalFailure || 'failed';
const RESULT_PATH = pc.resultPath      || 'analyzeResult';

// carry poll state forward (the previous item is the one that entered the Wait)
const prev = $('submit() — capture pollUrl').first().json._poll;
let state = { ...prev, ...($json._poll || {}) };
// after the first loop the state rides on the item; recover it if the HTTP node replaced the item
if (!state.pollUrl) state = { ...prev };

const res  = $json;                       // fullResponse
const body = res.body || {};
const headers = res.headers || {};
const httpStatus = res.statusCode;

state.attempt = (Number(state.attempt) || 0) + 1;
const elapsed = Date.now() - Number(state.startedAt);

// read provider status via configured path
const opStatus = String(STATUS_PATH.split('.').reduce((o,k)=> (o||{})[k], body) ?? '').toLowerCase();
const isSuccess = opStatus === String(SUCCESS).toLowerCase();
const isFailure = opStatus === String(FAILURE).toLowerCase();

// budget exhaustion -> terminal timeout
const overAttempts = state.attempt >= Number(state.maxAttempts);
const overElapsed  = elapsed      >= Number(state.maxElapsedMs);

let result = null, terminal = false, status = opStatus || 'running', error = null;
if (isSuccess) {
  terminal = true; status = 'succeeded';
  result = RESULT_PATH.split('.').reduce((o,k)=> (o||{})[k], body) ?? body;
} else if (isFailure) {
  terminal = true; status = 'failed';
  error = JSON.stringify(body.error || body).slice(0, 500);
} else if (httpStatus >= 400) {
  terminal = true; status = 'failed';
  error = `poll HTTP ${httpStatus}: ` + JSON.stringify(body).slice(0, 300);
} else if (overAttempts || overElapsed) {
  terminal = true; status = 'timeout';
  error = `OCR poll budget exhausted after ${state.attempt} attempts / ${Math.round(elapsed/1000)}s`;
}

// next wait: honor Retry-After, else configured interval
let waitMs = Number(state.intervalMs) || 2000;
const ra = headers['retry-after'] || headers['Retry-After'];
if (ra && !isNaN(Number(ra))) waitMs = Math.max(waitMs, Number(ra) * 1000);
if (httpStatus === 429) waitMs = Math.max(waitMs * 2, 5000);   // backoff on throttle
state.waitMs = waitMs;
state.terminal = terminal; state.status = status; state.error = error;
state.httpStatus = httpStatus;
console.log('[SW-005 poll] attempt=' + state.attempt + ' http=' + httpStatus
  + ' status=' + status + ' terminal=' + terminal
  + ' pages=' + ((result && result.pages) ? result.pages.length : 'n/a'));

return [{ json: { _poll: state, _result: result } }];

// ===== TEMPORARY VERIFICATION LOG — remove once confirmed. =====
// Confirms the item on the wire IS the terminal, successful poll before we permanently rely on it.
console.log({
  status: $json._poll?.status,
  terminal: $json._poll?.terminal,
  hasResult: !!$json._result,
  pages: $json._result?.pages?.length,
  paragraphs: $json._result?.paragraphs?.length,
});

// ===========================================================================
// TERMINAL POLL SELECTION — read the item on the wire. Do NOT reconstruct history.
//
// The item arriving here has already passed BOTH gates:
//     terminal?  ($json._poll.terminal === true)
//     succeeded? ($json._poll.status   === 'succeeded')
// so by construction it IS the terminal, successful poll. It carries _result.
//
// Do not use $('poll() — evaluate').all(...) to rediscover earlier loop runs: on n8n 2.29.9
// that reference does not expose the loop's run history to a downstream Code node (it returned
// only the FIRST run — a stale 'running' iteration — even when the execution viewer showed a
// later 'succeeded' run). The IF nodes already did the selection; trust the item.
// ===========================================================================
function terminalPoll() {
  const j = $json || {};
  const p = j._poll || {};
  if (p.terminal !== true || p.status !== 'succeeded') {
    // Defensive: this node is only wired to succeeded?[true]. If we ever get here with a
    // non-terminal item, the graph is wrong — fail loudly rather than emit an empty OCR object.
    throw new Error('SW-005 normalize(): received a non-terminal item '
      + '(status=' + (p.status || 'unknown') + ', terminal=' + p.terminal + '). '
      + 'normalize() must only be reached via succeeded?[true].');
  }
  if (j._result == null) {
    throw new Error('SW-005 normalize(): poll reported succeeded but _result is absent.');
  }
  return j;
}

// ===========================================================================
// OCR NORMALIZER — the ONE place that knows provider/format quirks.
// Downstream (SW-006/007/008/012/013) consumes a single normalized model and
// never needs to know whether the source was a PDF, an image, or a Word file.
//
//   Azure response
//        │
//        ▼
//   Normalizer ──┬── PDF / image : native pagination -> page + paragraph
//                └── DOCX        : no true pagination -> paragraph-first
//
// Pages are NEVER synthesized. A DOCX has no pages, so ocr.pages = [] and every
// paragraph carries page:null. That is the honest model (R-19 portability rule).
// ===========================================================================
function detectFormat(mimeType, fileName) {
  const mt = String(mimeType || '').toLowerCase();
  const fn = String(fileName || '').toLowerCase();
  if (mt.includes('pdf') || fn.endsWith('.pdf')) return 'pdf';
  if (mt.startsWith('image/') || /\.(png|jpe?g|tiff?|bmp|heif)$/.test(fn)) return 'image';
  if (mt.includes('wordprocessingml') || fn.endsWith('.docx') || fn.endsWith('.doc')) return 'docx';
  if (mt.includes('spreadsheetml') || fn.endsWith('.xlsx')) return 'xlsx';
  if (mt.includes('presentationml') || fn.endsWith('.pptx')) return 'pptx';
  return 'unknown';
}

function normalizeAzure(analyzeResult, sourceFormat, model) {
  // Formats with true, provider-reported pagination.
  const NATIVE_PAGINATION = { pdf: true, image: true };
  const hasNativePages = !!NATIVE_PAGINATION[sourceFormat];

  // ---- paragraphs: the PRIMARY unit. Azure returns these for BOTH pdf and docx.
  const src = analyzeResult.paragraphs || [];
  const paragraphs = src.map((para, i) => {
    let page = null;
    if (hasNativePages && para.boundingRegions && para.boundingRegions[0]) {
      page = para.boundingRegions[0].pageNumber ?? null;   // real page, never invented
    }
    return {
      index: i + 1,                       // 1-based document order (reading order)
      text: String(para.content || '').trim(),
      page,                               // null for docx — honest, not synthesized
      role: para.role || null,            // title | sectionHeading | pageHeader | ...
      offset: (para.spans && para.spans[0]) ? para.spans[0].offset : null,
    };
  }).filter(p => p.text);

  // ---- pages: ONLY when the format actually paginates. Empty for docx.
  let pages = [];
  if (hasNativePages) {
    const byPage = {};
    for (const p of paragraphs) {
      if (p.page == null) continue;
      (byPage[p.page] = byPage[p.page] || []).push(p.index);
    }
    pages = (analyzeResult.pages || []).map(pg => ({
      page: pg.pageNumber,
      confidence: (pg.words && pg.words.length)
        ? (pg.words.reduce((s, w) => s + (w.confidence || 0), 0) / pg.words.length) : 1,
      paragraphIndexes: byPage[pg.pageNumber] || [],
    }));
  }

  // ---- pageOf(): a bounding region's page, honest per format (null when unpaginated).
  const pageOf = (regions) => {
    if (!hasNativePages) return null;
    return (regions && regions[0] && regions[0].pageNumber != null) ? regions[0].pageNumber : null;
  };

  // ---- tables: normalized structure, not just a count. Cells are kept so a future
  //      consumer can render/reason over them without touching provider internals.
  const tables = (analyzeResult.tables || []).map((t, i) => ({
    index: i + 1,
    page: pageOf(t.boundingRegions),
    rowCount: t.rowCount ?? null,
    columnCount: t.columnCount ?? null,
    caption: (t.caption && t.caption.content) ? String(t.caption.content).trim() : null,
    cells: (t.cells || []).map(c => ({
      row: c.rowIndex, column: c.columnIndex,
      rowSpan: c.rowSpan ?? 1, columnSpan: c.columnSpan ?? 1,
      kind: c.kind || null,               // columnHeader | rowHeader | content | ...
      text: String(c.content || '').trim(),
    })),
  }));

  // ---- figures: locations + captions Azure already gives us. NOT image bytes — those
  //      require an explicit `output=figures` request parameter we do not currently send.
  //      Preserved now so image understanding can be added later without re-OCR.
  const figures = (analyzeResult.figures || []).map((f, i) => ({
    index: i + 1,
    id: f.id || null,
    page: pageOf(f.boundingRegions),
    caption: (f.caption && f.caption.content) ? String(f.caption.content).trim() : null,
    // element refs tie a figure back to the paragraphs it encloses (e.g. "/paragraphs/12")
    elements: Array.isArray(f.elements) ? f.elements.slice() : [],
    boundingRegions: f.boundingRegions || [],   // geometry retained for future cropping
    imageAvailable: false,   // true only if the provider was asked for figure images
  }));

  const content = typeof analyzeResult.content === 'string' ? analyzeResult.content : '';
  return {
    provider: 'azure',
    model: model || analyzeResult.modelId || null,
    sourceFormat,
    pagination: hasNativePages ? 'native' : 'none',
    readingOrderPresent: paragraphs.length > 0,
    paragraphs,
    pages,
    tables,     // normalized; [] when the document has none
    figures,    // normalized; [] when the document has none (or provider emits none)
    content,
    stats: {
      paragraphs: paragraphs.length,
      pages: pages.length,
      characters: content.length,
      tables: tables.length,
      figures: figures.length,
      tableCells: tables.reduce((s, t) => s + t.cells.length, 0),
      figuresWithCaption: figures.filter(f => f.caption).length,
    },
    raw: analyzeResult,   // for SW-009/010/011 evidence+citation. NEVER sent to an LLM.
  };
}

// ---- normalize() ---------------------------------------------------------
const incoming = $('When Executed by WF-001').first().json;
const final = terminalPoll();               // the item on the wire — no history lookup
const analyzeResult = final._result || {};

if (!analyzeResult.paragraphs && !analyzeResult.content) {
  throw new Error('SW-005: provider returned no paragraphs and no content '
    + '(status=' + ((final._poll && final._poll.status) || 'unknown') + ').');
}

const settings = $('Load OCR Provider Settings').first().json.settings || {};
const sourceFormat = detectFormat(incoming.mimeType, incoming.filename);
const ocr = normalizeAzure(analyzeResult, sourceFormat, settings.model);

console.log('[SW-005 normalize] ' + JSON.stringify({
  pollAttempt:  final._poll.attempt,
  sourceFormat: ocr.sourceFormat,
  pagination:   ocr.pagination,
  paragraphs:   ocr.stats.paragraphs,
  pages:        ocr.stats.pages,
  characters:   ocr.stats.characters,
  tables:       ocr.stats.tables,
  figures:      ocr.stats.figures,
  tableCells:   ocr.stats.tableCells,
}));

return [{ json: { ...incoming, ocr } }];

// Terminal failure/timeout. Read the item on the wire (succeeded?[false] already selected it).
// No run-history enumeration — see normalize() for why that is unreliable on n8n 2.29.9.
const incoming = $('When Executed by WF-001').first().json;
const p = ($json && $json._poll) || {};
return [{ json: { ...incoming, ocr: null,
  ocrError: { status: p.status || 'failed', attempts: p.attempt || 0,
              message: p.error || 'OCR failed' } } }];
